import { useState } from "react";

import api from "../services/api";

import Sidebar from "../components/Sidebar";

function ClearancePage() {

  const [form, setForm] = useState({
    employee: "",
    department: "",
    status: "Pending",
  });

  const submitClearance = async () => {

    try {

      await api.post(
        "/clearance",
        form
      );

      alert("Clearance Submitted");

    } catch (error) {

      alert("Error");
    }
  };

  return (

    <>

      <Sidebar />

      <div style={{ marginLeft: "240px", padding: "30px" }}>

        <h1>Clearance Approval</h1>

        <div
          style={{
            width: "400px",
            display: "flex",
            flexDirection: "column",
            gap: "15px",
            marginTop: "20px",
          }}
        >

          <input
            placeholder="Employee Name"
            onChange={(e) =>
              setForm({
                ...form,
                employee: e.target.value,
              })
            }
            style={{ padding: "10px" }}
          />

          <input
            placeholder="Department"
            onChange={(e) =>
              setForm({
                ...form,
                department: e.target.value,
              })
            }
            style={{ padding: "10px" }}
          />

          <select
            onChange={(e) =>
              setForm({
                ...form,
                status: e.target.value,
              })
            }
            style={{ padding: "10px" }}
          >
            <option>Pending</option>
            <option>Approved</option>
            <option>Rejected</option>
          </select>

          <button
            onClick={submitClearance}
            style={{
              padding: "12px",
              background: "#1e293b",
              color: "white",
              border: "none",
              cursor: "pointer",
            }}
          >
            Submit Clearance
          </button>

        </div>

      </div>

    </>
  );
}

export default ClearancePage;
